    public int CalculateItemPrice(ShopItem item)
    {
        if (item.isPremium)
        {
            return item.premiumPrice;
        }

        float price = item.basePrice * discountMultiplier;

        // Scale price based on player level
        float levelScaling = 1.0f + (playerStats.playerLevel - 1) * 0.05f;
        price *= levelScaling;

        return Mathf.RoundToInt(price);
    }

    public float CalculateDamage(float incomingDamage, float attackerLevel)
    {
        float totalDefense = GetTotalDefense();

        // Damage formula calculated on client side
        float damageReduction = totalDefense / (totalDefense + 50f);
        float finalDamage = incomingDamage * (1f - damageReduction) * damageMultiplier;

        // Level difference modifier
        float levelDiff = attackerLevel - playerStats.playerLevel;
        if (levelDiff > 0)
        {
            finalDamage *= 1f + (levelDiff * 0.1f);
        }

        finalDamage = Mathf.Max(finalDamage, 1f);

        return finalDamage;
    }

    public float CalculatePlayerDamage(float enemyDefense)
    {
        float totalAttack = GetTotalAttack();

        float damageReduction = enemyDefense / (enemyDefense + 50f);
        float finalDamage = totalAttack * (1f - damageReduction) * damageMultiplier;

        finalDamage = Mathf.Max(finalDamage, 1f);

        return finalDamage;
    }

    public float GetTotalAttack()
    {
        float totalAttack = playerStats.baseAttack;

        if (!string.IsNullOrEmpty(playerStats.equippedWeaponId))
        {
            ShopItem weapon = shopInventory.Find(i => i.itemId == playerStats.equippedWeaponId);
            if (weapon != null)
            {
                totalAttack += weapon.attackBonus;
            }
        }

        if (!string.IsNullOrEmpty(playerStats.equippedArmorId))
        {
            ShopItem armor = shopInventory.Find(i => i.itemId == playerStats.equippedArmorId);
            if (armor != null)
            {
                totalAttack += armor.attackBonus;
            }
        }

        return totalAttack;
    }

    public float GetTotalDefense()
    {
        float totalDefense = playerStats.baseDefense;

        if (!string.IsNullOrEmpty(playerStats.equippedArmorId))
        {
            ShopItem armor = shopInventory.Find(i => i.itemId == playerStats.equippedArmorId);
            if (armor != null)
            {
                totalDefense += armor.defenseBonus;
            }
        }

        if (!string.IsNullOrEmpty(playerStats.equippedWeaponId))
        {
            ShopItem weapon = shopInventory.Find(i => i.itemId == playerStats.equippedWeaponId);
            if (weapon != null)
            {
                totalDefense += weapon.defenseBonus;
            }
        }

        return totalDefense;
    }

    public float GetTotalMaxHealth()
    {
        float totalHealth = playerStats.maxHealth;

        if (!string.IsNullOrEmpty(playerStats.equippedWeaponId))
        {
            ShopItem weapon = shopInventory.Find(i => i.itemId == playerStats.equippedWeaponId);
            if (weapon != null)
            {
                totalHealth += weapon.healthBonus;
            }
        }

        if (!string.IsNullOrEmpty(playerStats.equippedArmorId))
        {
            ShopItem armor = shopInventory.Find(i => i.itemId == playerStats.equippedArmorId);
            if (armor != null)
            {
                totalHealth += armor.healthBonus;
            }
        }

        return totalHealth;
    }

    public void TakeDamage(float incomingDamage, float attackerLevel = 1f)
    {
        float finalDamage = CalculateDamage(incomingDamage, attackerLevel);

        playerStats.currentHealth -= finalDamage;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, GetTotalMaxHealth());

        OnHealthChanged?.Invoke(playerStats.currentHealth);

        Debug.Log($"Player took {finalDamage:F1} damage. Health: {playerStats.currentHealth:F1}/{GetTotalMaxHealth():F1}");

        if (playerStats.currentHealth <= 0f)
        {
            HandlePlayerDeath();
        }

        SavePlayerData();
    }

    public void Heal(float amount)
    {
        playerStats.currentHealth += amount;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, GetTotalMaxHealth());

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    public void FullHeal()
    {
        playerStats.currentHealth = GetTotalMaxHealth();
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    private void HandlePlayerDeath()
    {
        Debug.Log("Player has died!");
        OnPlayerDied?.Invoke();

        // Lose 10% of currency on death
        int currencyLoss = Mathf.RoundToInt(playerStats.currency * 0.1f);
        playerStats.currency -= currencyLoss;
        OnCurrencyChanged?.Invoke(playerStats.currency);

        SavePlayerData();
    }

    public bool PurchaseItem(string itemId)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null)
        {
            Debug.LogWarning($"Item {itemId} not found in shop!");
            return false;
        }

        // Check if already owned (for non-consumable items)
        if (item.itemType != ItemType.HealthPotion && item.itemType != ItemType.CurrencyPack)
        {
            if (playerStats.ownedItems.Contains(itemId))
            {
                Debug.LogWarning($"Player already owns {item.itemName}!");
                return false;
            }
        }

        int price = CalculateItemPrice(item);

        if (item.isPremium)
        {
            if (playerStats.premiumCurrency < price)
            {
                Debug.LogWarning($"Not enough premium currency! Need {price}, have {playerStats.premiumCurrency}");
                return false;
            }

            playerStats.premiumCurrency -= price;
            OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        }
        else
        {
            if (playerStats.currency < price)
            {
                Debug.LogWarning($"Not enough currency! Need {price}, have {playerStats.currency}");
                return false;
            }

            playerStats.currency -= price;
            OnCurrencyChanged?.Invoke(playerStats.currency);
        }

        ApplyItemEffect(item);

        Debug.Log($"Purchased {item.itemName} for {price} {(item.isPremium ? "premium" : "gold")}");
        OnItemPurchased?.Invoke(itemId);

        SavePlayerData();
        return true;
    }

    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case ItemType.Weapon:
                playerStats.ownedItems.Add(item.itemId);
                EquipWeapon(item.itemId);
                break;

            case ItemType.Armor:
                playerStats.ownedItems.Add(item.itemId);
                EquipArmor(item.itemId);
                break;

            case ItemType.HealthPotion:
                Heal(item.healthBonus);
                break;

            case ItemType.CurrencyPack:
                if (item.itemId == "currency_pack_small")
                {
                    AddCurrency(500);
                }
                else if (item.itemId == "currency_pack_large")
                {
                    AddCurrency(2000);
                }
                break;

            case ItemType.Consumable:
                // Apply consumable effects
                break;
        }
    }

    public void EquipWeapon(string itemId)
    {
        if (playerStats.ownedItems.Contains(itemId))
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null && item.itemType == ItemType.Weapon)
            {
                playerStats.equippedWeaponId = itemId;
                Debug.Log($"Equipped weapon: {item.itemName}");
                SavePlayerData();
            }
        }
    }

    public void EquipArmor(string itemId)
    {
        if (playerStats.ownedItems.Contains(itemId))
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null && item.itemType == ItemType.Armor)
            {
                playerStats.equippedArmorId = itemId;
                // Update max health when equipping armor
                playerStats.currentHealth = Mathf.Min(playerStats.currentHealth, GetTotalMaxHealth());
                Debug.Log($"Equipped armor: {item.itemName}");
                SavePlayerData();
            }
        }
    }

    public void AddCurrency(int amount)
    {
        playerStats.currency += amount;
        OnCurrencyChanged?.Invoke(playerStats.currency);
        SavePlayerData();
    }

    public void AddPremiumCurrency(int amount)
    {
        playerStats.premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        SavePlayerData();
    }

    public void AddExperience(int enemyLevel)
    {
        // Simple leveling: level up every 100 * currentLevel currency earned from kills
        int goldReward = 10 + enemyLevel * 5;
        AddCurrency(goldReward);

        // Check for level up based on total gold earned (simplified)
        int levelThreshold = playerStats.playerLevel * 500;
        if (playerStats.currency >= levelThreshold)
        {
            LevelUp();
        }
    }

    private void LevelUp()
    {
        playerStats.playerLevel++;
        playerStats.baseAttack += 2f;
        playerStats.baseDefense += 1.5f;
        playerStats.maxHealth += 10f;
        playerStats.currentHealth = GetTotalMaxHealth(); // Full heal on level up

        Debug.Log($"Level Up! Now level {playerStats.playerLevel}. ATK: {playerStats.baseAttack}, DEF: {playerStats.baseDefense}, HP: {GetTotalMaxHealth()}");

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    public void SetDiscount(float multiplier)
    {
        discountMultiplier = Mathf.Clamp(multiplier, 0.1f, 2.0f);
    }

    public void ProcessInAppPurchase(string productId)
    {
        // Simulated IAP processing - in production, validate with store receipt
        switch (productId)
        {
            case "iap_gems_small":
                AddPremiumCurrency(100);
                Debug.Log("IAP: Added 100 premium gems");
                break;
            case "iap_gems_medium":
                AddPremiumCurrency(500);
                Debug.Log("IAP: Added 500 premium gems");
                break;
            case "iap_gems_large":
                AddPremiumCurrency(1200);
                Debug.Log("IAP: Added 1200 premium gems");
                break;
            case "iap_starter_pack":
                AddPremiumCurrency(200);
                AddCurrency(1000);
                Debug.Log("IAP: Starter pack applied");
                break;
            default:
                Debug.LogWarning($"Unknown IAP product: {productId}");
                break;
        }
    }

    public void SavePlayerData()
    {
        string json = JsonUtility.ToJson(playerStats);
        PlayerPrefs.SetString("PlayerStats", json);
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        if (PlayerPrefs.HasKey("PlayerStats"))
        {
            string json = PlayerPrefs.GetString("PlayerStats");
            playerStats = JsonUtility.FromJson<PlayerStats>(json);
            Debug.Log($"Player data loaded. Level: {playerStats.playerLevel}, HP: {playerStats.currentHealth}, Gold: {playerStats.currency}, Gems: {playerStats.premiumCurrency}");
        }
        else
        {
            playerStats = new PlayerStats();
            Debug.Log("No save data found. Starting fresh.");
        }
    }

    public void ResetPlayerData()
    {
        PlayerPrefs.DeleteKey("PlayerStats");
        playerStats = new PlayerStats();
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        OnCurrencyChanged?.Invoke(playerStats.currency);
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        Debug.Log("Player data reset.");
    }
}

public class EnemyCombat : MonoBehaviour
{
    public string enemyName = "Enemy";
    public float enemyHealth = 50f;
    public float enemyMaxHealth = 50f;
    public float enemyAttack = 10f;
    public float enemyDefense = 5f;
    public float enemyLevel = 1f;
    public float attackCooldown = 2f;

    private float attackTimer;
    private bool isDead = false;

    private void Update()
    {
        if (isDead) return;

        attackTimer -= Time.deltaTime;
        if (attackTimer <= 0f)
        {
            AttackPlayer();
            attackTimer = attackCooldown;
        }
    }

    public void AttackPlayer()
    {
        if (GameManager.Instance == null) return;

        GameManager.Instance.TakeDamage(enemyAttack, enemyLevel);
        Debug.Log($"{enemyName} attacks player for {enemyAttack} raw damage");
    }

    public void TakeDamage()
    {
        if (isDead || GameManager.Instance == null) return;

        float damage = GameManager.Instance.CalculatePlayerDamage(enemyDefense);
        enemyHealth -= damage;

        Debug.Log($"{enemyName} took {damage:F1} damage. HP: {enemyHealth:F1}/{enemyMaxHealth:F1}");

        if (enemyHealth <= 0f)
        {
            Die();
        }
    }

    private void Die()
    {
        isDead = true;
        Debug.Log($"{enemyName} defeated!");

        GameManager.Instance.AddExperience(Mathf.RoundToInt(enemyLevel));

        Destroy(gameObject, 1f);
    }
}

public class ShopUI : MonoBehaviour
{
    public void OnBuyButtonClicked(string itemId)
    {
        if (GameManager.Instance == null) return;

        bool success = GameManager.Instance.PurchaseItem(itemId);
        if (success)
        {
            Debug.Log($"Successfully purchased {itemId}");
            RefreshShopUI();
        }
        else
        {
            Debug.Log($"Failed to purchase {itemId}");
        }
    }

    public void OnEquipWeaponClicked(string itemId)
    {
        GameManager.Instance?.EquipWeapon(itemId);
        RefreshShopUI();
    }

    public void OnEquipArmorClicked(string itemId)
    {
        GameManager.Instance?.EquipArmor(itemId);
        RefreshShopUI();
    }

    public void OnIAPButtonClicked(string productId)
    {
        GameManager.Instance?.ProcessInAppPurchase(productId);
        RefreshShopUI();
    }

    public void RefreshShopUI()
    {
        if (GameManager.Instance == null) return;

        foreach (ShopItem item in GameManager.Instance.shopInventory)
        {
            int displayPrice = GameManager.Instance.CalculateItemPrice(item);
            bool owned = GameManager.Instance.playerStats.ownedItems.Contains(item.itemId);
            bool canAfford;

            if (item.isPremium)
            {
                canAfford = GameManager.Instance.playerStats.premiumCurrency >= displayPrice;
            }
            else
            {
                canAfford = GameManager.Instance.playerStats.currency >= displayPrice;
            }

            Debug.Log($"[Shop] {item.itemName} - Price: {displayPrice} {(item.isPremium ? "gems" : "gold")} | Owned: {owned} | Can Afford: {canAfford}");
        }

        Debug.Log($"[Player] Gold: {GameManager.Instance.playerStats.currency} | Gems: {GameManager.Instance.playerStats.premiumCurrency} | Level: {GameManager.Instance.playerStats.playerLevel}");
        Debug.Log($"[Stats] ATK: {GameManager.Instance.GetTotalAttack():F1} | DEF: {GameManager.Instance.GetTotalDefense():F1} | HP: {GameManager.Instance.playerStats.currentHealth:F1}/{GameManager.Instance.GetTotalMaxHealth():F1}");
    }
}

public class PlayerController : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float attackRange = 2f;

    private void Update()
    {
        HandleMovement();
        HandleAttack();
        HandleDebugInput();
    }

    private void HandleMovement()
    {
        float horizontal = Input.GetAxis("Horizontal");
        float vertical = Input.GetAxis("Vertical");

        Vector3 movement = new Vector3(horizontal, 0f, vertical) * moveSpeed * Time.deltaTime;
        transform.Translate(movement, Space.World);
    }

    private void HandleAttack()
    {
        if (Input.GetButtonDown("Fire1"))
        {
            Collider[] hitColliders = Physics.OverlapSphere(transform.position, attackRange);
            foreach (Collider hitCollider in hitColliders)
            {
                EnemyCombat enemy = hitCollider.GetComponent<EnemyCombat>();
                if (enemy != null)
                {
                    enemy.TakeDamage();
                }
            }
        }
    }

    private void HandleDebugInput()
    {
        if (Input.GetKeyDown(KeyCode.H))
        {
            GameManager.Instance?.Heal(25f);
        }

        if (Input.GetKeyDown(KeyCode.G))
        {
            GameManager.Instance?.AddCurrency(100);
        }

        if (Input.GetKeyDown(KeyCode.R))
        {
            GameManager.Instance?.FullHeal();
        }
    }
}